#include <vector>
using namespace std;

class FenwickTree {
    vector<long long> tree;
    int size;
public:
    FenwickTree(int s) : size(s), tree(s + 2, 0) {}
    void update(int index, long long delta) {
        index += 1; // 1-based
        while (index <= size) {
            tree[index] += delta;
            index += index & -index;
        }
    }
    long long query(int index) {
        index += 1; // 1-based
        long long res = 0;
        while (index > 0) {
            res += tree[index];
            index -= index & -index;
        }
        return res;
    }
    long long range_query(int l, int r) {
        return query(r) - query(l - 1);
    }
};

vector<long long> solve(vector<long long> nums, vector<vector<long long>> queries) {
    int n = nums.size();
    vector<int> depths(n);
    for (int i = 0; i < n; ++i) {
        long long x = nums[i];
        int d = 0;
        while (x != 1) {
            x = __builtin_popcountll(x);
            d++;
        }
        depths[i] = d;
    }
    vector<FenwickTree> ft(6);
    for (int i = 0; i < 6; ++i) {
        ft[i] = FenwickTree(n);
    }
    for (int i = 0; i < n; ++i) {
        int d = depths[i];
        ft[d].update(i, 1);
    }
    vector<long long> answer;
    for (auto& q : queries) {
        if (q[0] == 1) {
            int l = q[1], r = q[2], k = q[3];
            if (k < 0 || k > 5) {
                answer.push_back(0);
                continue;
            }
            answer.push_back(ft[k].range_query(l, r));
        } else {
            int idx = q[1], val = q[2];
            long long old_val = nums[idx];
            int old_depth = depths[idx];
            ft[old_depth].update(idx, -1);
            long long x = val;
            int new_depth = 0;
            while (x != 1) {
                x = __builtin_popcountll(x);
                new_depth++;
            }
            ft[new_depth].update(idx, 1);
            nums[idx] = val;
            depths[idx] = new_depth;
        }
    }
    return answer;
}
